@ARTICLE{10.3390/ijms27020756,
	author = {Dairi G(1)(2) and Ibrahim MA(2) and Mahri SA(2) and Al-Regaiey K(3) and Malik SS(2) and Mohammad S(2).},
	title = {RNA-Binding Proteins in Adipose Biology: From Mechanistic Understanding to Therapeutic Opportunities.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Obesity, defined by excessive body fat accumulation, is strongly associated with dysfunction of adipose tissue, a major regulator of whole-body energy balance and metabolic health. Dysfunctional adipose tissue is characterized by altered adipokine secretion, impaired insulin sensitivity, and chronic low-grade inflammation, all of which contribute to obesity-related comorbidities such as type 2 diabetes, cardiovascular disease, and certain cancers. Understanding how obesity disrupts adipose tissue biology is essential for developing strategies to mitigate these metabolic risks. In recent years, RNA-binding proteins (RBPs) have emerged as important regulators of energy metabolism. By controlling post-transcriptional gene expression, RBPs influence RNA stability, localization, and translation, thereby shaping key cellular processes. Dysregulation of specific RBPs has been implicated in obesity and metabolic disorders, with several shown to affect adipogenesis, lipid handling, thermogenesis, and insulin sensitivity across different adipose depots. Their ability to direct the fate of transcripts involved in metabolic homeostasis positions RBPs as critical nodes linking adipose dysfunction to systemic disease. This review provides a mechanistic overview of RBP functions in adipose biology, highlights how their dysregulation can reinforce metabolic dysfunction, and identifies gaps and future directions for exploring RBPs and their RNA networks as potential therapeutic targets for obesity and related metabolic diseases.},
	doi = {10.3390/ijms27020756},
	pmid = {41596407 [Indexed for MEDLINE]},
	note = {PMC12840790}
}

@ARTICLE{10.3390/genes17010093,
	author = {Yu Y(1) and Liu S(1) and Yang J(1) and Xu S(1).},
	title = {Transcriptome Analysis of Adipose Tissues from Five Sheep Breeds Reveals Key Genes Involved in Fat Deposition.},
	journal = {Genes (Basel)},
	year = {2026},
	abstract = {BACKGROUND: Sheep (Ovis aries) exhibit significant diversity in adipose tissue deposition, which influences meat quality, environmental adaptation, and economic value. Tail fat, in particular, varies widely among breeds, yet the transcriptomic basis of this variation remains incompletely understood. This study aims to systematically compare the transcriptional profiles of five adipose depots across five sheep breeds to identify molecular mechanisms underlying fat deposition and tail phenotype divergence. METHODS: We analyzed 250 publicly available RNA-seq samples from five adipose tissues (caul, subcutaneous, perirenal, intermuscular, and tail fat) of five sheep breeds (Altay, Tibetan, Merino, Wadi, Small-tailed Han). Data were processed using FastQC, STAR, and featureCounts. Differential expression analysis was performed with DESeq2, followed by GO and KEGG enrichment analyses. Breeds were grouped into three tail phenotypes: fat-tailed, short fat-tailed, and thin-tailed. Cross-tissue and phenotype-specific pathway analyses were conducted to identify key regulatory genes. RESULTS: Transcriptional divergence was most pronounced in subcutaneous and intermuscular fat, while tail fat exhibited both conserved and phenotype-specific pathways. Fat-tailed breeds showed enrichment in mitochondrial oxidative phosphorylation and lipid biosynthesis genes (TAFAZZIN, GPAM, COQ family). Short fat-tailed breeds were characterized by extracellular matrix remodeling genes (MMP9, MMP12, MMP19). Thin-tailed sheep lacked these pro-lipogenic and structural remodeling pathways. A dual-axis model of tail fat development is proposed to explain phenotypic diversity. CONCLUSIONS: This study reveals that distinct molecular mechanisms underpin tail fat phenotypes in sheep: fat-tailed breeds prioritize metabolic efficiency, short fat-tailed breeds rely on ECM remodeling, and thin-tailed breeds lack these enhancements. The identified candidate genes may serve as potential targets for molecular breeding strategies aimed at optimizing fat deposition and adaptive traits in sheep.},
	doi = {10.3390/genes17010093},
	pmid = {41595512 [Indexed for MEDLINE]},
	note = {PMC12841507}
}

@ARTICLE{10.3390/biom16010101,
	author = {Zhu Q(1)(2) and Hu Y(1)(2) and Li M(1)(2) and Yang H(1)(2) and Zhao L(1)(2) and Zhao Y(1)(2).},
	title = {N(6)-Methyladenosine (m(6)A)-Mediated Regulation of Lipid Metabolism: Molecular Mechanisms, Pathological Implications, and Therapeutic Perspectives.},
	journal = {Biomolecules},
	year = {2026},
	abstract = {Dysregulated lipid metabolism constitutes the fundamental etiology underlying the global burden of obesity and its associated metabolic disorders. N6-methyladenosine (m6A) is the most abundant reversible chemical modification on messenger RNA and influences virtually every aspect of RNA metabolism. Recent studies demonstrate that m6A mediates regulatory networks governing lipid metabolism and contributes to the pathogenesis of multiple metabolic diseases. However, the precise roles of m6A in lipid metabolism and related metabolic disorders remain incompletely understood. This review positions m6A modification as a central epigenetic switch that governs lipid homeostasis. We first summarize the molecular components of the dynamic m6A regulatory machinery and delineate the mechanisms by which it controls key lipid metabolic processes, with an emphasis on adipogenesis, thermogenesis and lipolysis. Building on this, we further discuss how dysregulated m6A acts as a shared upstream driver linking obesity, type 2 diabetes (T2D), metabolic dysfunction-associated steatotic liver disease (MASLD), and insulin resistance through tissue-specific and inter-organ communication mechanisms. We also evaluate the potential of targeting m6A regulators as therapeutic strategies for precision intervention in metabolic diseases. Ultimately, deciphering the complex interplay between m6A modification and lipid homeostasis offers a promising frontier for the development of epitranscriptome-targeted precision medicine against obesity and its associated metabolic disorders.},
	doi = {10.3390/biom16010101},
	pmid = {41594642 [Indexed for MEDLINE]},
	note = {PMC12839223}
}

